def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    main_subject = None
    for subject, triples_list in subject_map.items():
        if any(p in ["cityServed", "location", "runwayLength", "runwayName", "elevationAboveTheSeaLevel"] for p, _ in triples_list):
            main_subject = subject
            break

    if not main_subject and subject_map:
        main_subject = list(subject_map.keys())[0]

    if not main_subject:
        return "."

    sentence = main_subject
    details = []
    sub_details = {}

    for subject, triples_list in subject_map.items():
        for predicate, obj in triples_list:
            if subject not in sub_details:
                sub_details[subject] = []
            if predicate == "cityServed":
                sub_details[subject].append(f"serves the city of {obj}")
            elif predicate == "mayor":
                sub_details[subject].append(f"has a mayor of {obj}")
            elif predicate == "isPartOf":
                sub_details[subject].append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                sub_details[subject].append(f"is operated by {obj}")
            elif predicate == "location":
                sub_details[subject].append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                sub_details[subject].append(f"is {obj} metres above sea level")
            elif predicate == "runwayLength":
                sub_details[subject].append(f"has a runway length of {obj} metres")
            elif predicate == "country":
                sub_details[subject].append(f"is located in {obj}")
            elif predicate == "capital":
                sub_details[subject].append(f"has {obj} as its capital")
            elif predicate == "language":
                sub_details[subject].append(f"where the language is {obj}")
            elif predicate == "leader":
                sub_details[subject].append(f"whose leader is {obj}")
            elif predicate == "owner":
                sub_details[subject].append(f"is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                sub_details[subject].append(f"has a first runway length of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                sub_details[subject].append(f"has a first runway made of {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                sub_details[subject].append(f"has a third runway length of {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                sub_details[subject].append(f"has an ICAO location identifier of {obj}")
            elif predicate == "locationIdentifier":
                sub_details[subject].append(f"has a location identifier of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                sub_details[subject].append(f"is {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                sub_details[subject].append(f"has an IATA identifier of {obj}")
            elif predicate == "nativeName":
                sub_details[subject].append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                sub_details[subject].append(f"whose governing party is {obj}")
            elif predicate == "runwayName":
                sub_details[subject].append(f"has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                sub_details[subject].append(f"has a runway made of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                sub_details[subject].append(f"is {obj} metres above sea level")
            elif predicate == "demonym":
                sub_details[subject].append(f"whose people are called {obj}")
            elif predicate == "officialLanguage":
                sub_details[subject].append(f"has {obj} as its official language")
            else:
                sub_details[subject].append(f"has a {predicate} of {obj}")

    for subject, sub_detail in sub_details.items():
        if subject == main_subject:
            details.append(", ".join(sub_detail))
        else:
            details.append(f"{subject} {', '.join(sub_detail)}")

    if details:
        sentence += " " + ", and ".join(details)

    return sentence + "."

